mapper.select:
SELECT si.*, s.school_name AS schoolName, m.major_name AS majorName, cp.candidate_name AS candidateName FROM supplement_invitation si LEFT JOIN school s ON si.school_id = s.school_id LEFT JOIN major m ON si.invitation_major_id = m.major_id LEFT JOIN candidate_push cp ON si.push_id = cp.push_id WHERE 1=1
AND si.school_id = #{schoolId}
AND si.status = #{status}
AND si.supplement_round = #{round}
AND (si.candidate_id ILIKE '%' || #{candidateKeyword} || '%' OR cp.candidate_name ILIKE '%' || #{candidateKeyword} || '%')
ORDER BY si.sent_at DESC

SELECT * FROM supplement_invitation
WHERE status = 'INVITED'
  AND expires_at <= #{now}

SELECT si.*, s.school_name AS schoolName, m.major_name AS majorName, cp.candidate_name AS candidateName FROM supplement_invitation si LEFT JOIN school s ON si.school_id = s.school_id LEFT JOIN major m ON si.invitation_major_id = m.major_id LEFT JOIN candidate_push cp ON si.push_id = cp.push_id WHERE 1=1
AND si.school_id = #{schoolId}
AND si.status = #{status}
AND si.supplement_round = #{round}
AND (si.candidate_id ILIKE '%' || #{candidateKeyword} || '%' OR cp.candidate_name ILIKE '%' || #{candidateKeyword} || '%')
ORDER BY si.sent_at DESC LIMIT 500
